def get_year_range(start_year, end_year):
    if start_year == None:
        return ''
    elif end_year == None or start_year >= end_year:
        return f'{start_year}'
    elif start_year // 100 == end_year // 100:
        return f'{start_year}-{end_year % 100:02d}'
    else:
        return f'{start_year}-{end_year}'

